class Solution {
    public boolean backspaceCompare(String s, String t) {
        int i = s.length() - 1;
        int j = t.length() - 1;
        int skipS = 0, skipT = 0;

        while (i >= 0 || j >= 0) {
            char c = '\0';
            // Process string s
            while (i >= 0) {
                if (s.charAt(i) == '#') {
                    skipS++;
                    i--;
                } else if (skipS > 0) {
                    skipS--;
                    i--;
                } else {
                    c = s.charAt(i);
                    i--;
                    break;
                }
            }

            // Process string t
            char d = '\0';
            while (j >= 0) {
                if (t.charAt(j) == '#') {
                    skipT++;
                    j--;
                } else if (skipT > 0) {
                    skipT--;
                    j--;
                } else {
                    d = t.charAt(j);
                    j--;
                    break;
                }
            }

            // Compare characters
            if (c == '\0' && d == '\0') {
                continue;
            } else if (c == '\0' || d == '\0') {
                return false;
            } else if (c != d) {
                return false;
            }
        }

        return true;
    }
